const projeto = $('Limit — 1 projeto').item.json;
const arquivos = $input.all().map(i => i.json);

const lista = arquivos.map(a => ({
  nome: a.nome,
  tipo: a.tipo,
  drive_file_id: a.drive_file_id
}));

const foto = lista.find(a => a.tipo === 'foto') || null;

return [{
  json: {
    projeto_id: projeto.id,
    brief: projeto.brief || '',
    tipo_entrada: projeto.tipo_entrada,
    pasta_drive_id: projeto.pasta_drive_id,
    arquivos: lista,
    foto_drive_id: foto ? foto.drive_file_id : null,
    foto_nome: foto ? foto.nome : null,
    foto_mime: 'image/jpeg'
  }
}];

const ctx = $('Code — montar contexto').item.json;
const bin = items[0].binary && items[0].binary.data;
let mediaType = (bin && bin.mimeType) ? bin.mimeType : ctx.foto_mime;
if (mediaType === 'image/jpg') mediaType = 'image/jpeg';

let imageBlock = null;
if (bin) {
  const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
  imageBlock = {
    type: 'image',
    source: {
      type: 'base64',
      media_type: mediaType,
      data: buffer.toString('base64')
    }
  };
}

return [{ json: { ...ctx, imageBlock } }];

const projetoId = $('Code — prompt Diretor').item.json.projeto_id;
const resp = $input.first().json;

const text = (resp.content || [])
  .filter(b => b.type === 'text')
  .map(b => b.text)
  .join('\n')
  .trim();

let parsed;
try {
  const cleaned = text.replace(/^```json\s*/i, '').replace(/```$/i, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = {
    projeto_id: projetoId,
    agente: 'diretor',
    status: 'erro',
    resultado: {},
    qualidade: 0,
    problemas: ['Resposta do Claude não era JSON válido: ' + e.message, text.slice(0, 500)],
    proximo_agente: null
  };
}

parsed.projeto_id = parsed.projeto_id || projetoId;
parsed.agente = 'diretor';

// Normalizar status (modelos às vezes devolvem "completo", "success", etc.)
const raw = String(parsed.status || '').toLowerCase().trim();
const okAliases = new Set(['ok', 'completo', 'complete', 'success', 'sucesso', 'done']);
const reviewAliases = new Set(['precisa_revisao', 'revisao', 'review', 'needs_review']);
const errAliases = new Set(['erro', 'error', 'fail', 'failed']);

if (okAliases.has(raw)) parsed.status = 'ok';
else if (reviewAliases.has(raw)) parsed.status = 'precisa_revisao';
else if (errAliases.has(raw)) parsed.status = 'erro';
else if (parsed.resultado && (parsed.resultado.plano_de_conteudos || parsed.resultado.tema)) {
  // Tem plano útil mas status fora do enum → tratar como ok
  parsed.status = 'ok';
  parsed.problemas = (parsed.problemas || []).concat(['status original normalizado: ' + raw]);
} else {
  parsed.status = 'erro';
}

// qualidade: schema pede 0-100 integer
if (parsed.qualidade && typeof parsed.qualidade === 'object') {
  const n = Number(parsed.qualidade.nota);
  parsed.qualidade = Number.isFinite(n) ? Math.round(n * (n <= 10 ? 10 : 1)) : 0;
}

const estado = parsed.status === 'ok' ? 'planeado' : 'erro';

return [{
  json: {
    projeto_id: projetoId,
    estado,
    plano: parsed,
    status_agente: parsed.status,
    mensagem_log: parsed.status === 'ok'
      ? 'Plano do Diretor gravado'
      : ('Diretor: ' + (parsed.status || 'erro'))
  }
}];
